BEGIN;

-- Booking Submitted
INSERT INTO email_templates (name, stage, channel, subject, body, sms_body, trigger_type, description) VALUES (
  E'Booking Submitted', E'booking_submitted', E'both',
  E'Request received — {{booking_code}}',
  E'Hi {{first_name}},\n\nThanks for choosing JD Coastal Cars. We''ve got your request and we''re reviewing it now — you''ll hear back within a few hours during business hours.\n\nReference: {{booking_code}}\nVehicle: {{vehicle}}\nPickup: {{pickup_date}} at {{pickup_time}}\nReturn: {{return_date}} at {{return_time}}\nTotal: ${{total_cost}}\n\nOnce we confirm availability, we''ll send a link to sign your agreement and pay.\n\nQuestions? Call or text (908) 692-8492.\n\nJD Coastal Cars\nPalm Bay, FL',
  E'Thanks {{first_name}} — we''ve got your request with JD Coastal Cars.\n\n{{vehicle}}\n{{pickup_date}} – {{return_date}}\nRef {{booking_code}}\n\nWe''ll confirm within a few hours. — JD Coastal Cars',
  E'automated', E'Sent immediately when a customer submits a booking request.'
)
ON CONFLICT (stage) DO UPDATE SET
  name = EXCLUDED.name, channel = EXCLUDED.channel, subject = EXCLUDED.subject,
  body = EXCLUDED.body, sms_body = EXCLUDED.sms_body,
  trigger_type = EXCLUDED.trigger_type, description = EXCLUDED.description;

-- Booking Approved
INSERT INTO email_templates (name, stage, channel, subject, body, sms_body, trigger_type, description) VALUES (
  E'Booking Approved', E'booking_approved', E'both',
  E'You’re confirmed — {{vehicle}} ({{booking_code}})',
  E'Hi {{first_name}},\n\nYou''re confirmed. Sign your agreement and pay to lock it in — that''s the only step left.\n\nReference: {{booking_code}}\nVehicle: {{vehicle}}\nPickup: {{pickup_date}} at {{pickup_time}}\nReturn: {{return_date}} at {{return_time}}\nMileage: {{mileage_policy}}\nTotal: ${{total_cost}}\n\nWe''ll text your exact address, parking spot, and lockbox code 24 hours before pickup. Prefer delivery? Just reply and we''ll set it up.\n\nQuestions? Call or text (908) 692-8492.\n\nJD Coastal Cars\nPalm Bay, FL',
  E'You''re confirmed, {{first_name}}!\n\n{{vehicle}}\nPickup {{pickup_date}} at {{pickup_time}}\nRef {{booking_code}}\n\nSign & pay to lock it in: {{confirm_link}}\n\nWe''ll text pickup details the day before. — JD Coastal Cars',
  E'automated', E'Sent when the admin approves a booking request.'
)
ON CONFLICT (stage) DO UPDATE SET
  name = EXCLUDED.name, channel = EXCLUDED.channel, subject = EXCLUDED.subject,
  body = EXCLUDED.body, sms_body = EXCLUDED.sms_body,
  trigger_type = EXCLUDED.trigger_type, description = EXCLUDED.description;

-- Booking Declined
INSERT INTO email_templates (name, stage, channel, subject, body, sms_body, trigger_type, description) VALUES (
  E'Booking Declined', E'booking_declined', E'both',
  E'About your booking request — {{booking_code}}',
  E'Hi {{first_name}},\n\nUnfortunately we can''t confirm this booking.\n\nReference: {{booking_code}}\nVehicle: {{vehicle}}\nDates: {{pickup_date}} – {{return_date}}\n\nWhy: {{decline_reason}}\n\nWe may have another vehicle open for your dates. Call us at (908) 692-8492 and we''ll find you something that works.\n\nJD Coastal Cars\nPalm Bay, FL',
  E'Hi {{first_name}}, we couldn''t confirm the {{vehicle}} for {{pickup_date}}–{{return_date}}.\n\n{{decline_reason}}\n\nCall (908) 692-8492 and we''ll find an alternative. — JD Coastal Cars',
  E'automated', E'Sent when the admin declines a booking request.'
)
ON CONFLICT (stage) DO UPDATE SET
