-- Payment Confirmed
INSERT INTO email_templates (name, stage, channel, subject, body, sms_body, trigger_type, description) VALUES (
  E'Payment Confirmed', E'payment_confirmed', E'both',
  E'Payment received — you’re all set ({{booking_code}})',
  E'Hi {{first_name}},\n\nPayment received and your booking is confirmed. Your receipt and pickup steps are below.\n\nEverything lives in your portal — receipt, check-in, messages, and extensions. {{#if deposit_amount}}Your ${{deposit_amount}} deposit is fully refundable and returns 3–5 business days after inspection.{{/if}}\n\nQuestions? Call or text (908) 692-8492.\n\nJD Coastal Cars\nPalm Bay, FL',
  E'Payment confirmed, {{first_name}} — you''re all set!\n\n{{vehicle}}\nPickup {{pickup_date}} at {{pickup_time}}\nRef {{booking_code}}\n\nYour portal: {{portal_link}}\nWe''ll text pickup details the day before. — JD Coastal Cars',
  E'automated', E'Sent when a payment succeeds. Itemized receipt + pickup steps are added automatically above this body.'
)
ON CONFLICT (stage) DO UPDATE SET
  name = EXCLUDED.name, channel = EXCLUDED.channel, subject = EXCLUDED.subject,
  body = EXCLUDED.body, sms_body = EXCLUDED.sms_body,
  trigger_type = EXCLUDED.trigger_type, description = EXCLUDED.description;

-- Ready for Pickup
INSERT INTO email_templates (name, stage, channel, subject, body, sms_body, trigger_type, description) VALUES (
  E'Ready for Pickup', E'ready_for_pickup', E'both',
  E'Your {{vehicle}} is ready — {{booking_code}}',
  E'Hi {{first_name}},\n\nYour vehicle is cleaned, prepped, and ready.\n\nVehicle: {{vehicle}}\nReference: {{booking_code}}\nPickup: {{pickup_date}} at {{pickup_time}}\n\nGetting your keys\n765 Altara Ln NE, Palm Bay, FL 32907 — park and walk to the back of the building. Your vehicle has a key lockbox on the window. Enter code {{lockbox_code}}, take the key, and remove the lockbox before driving.\n\nA few house rules: return with the same fuel level, no smoking, no pets ($150 cleaning fee each). Text us when you arrive.\n\nJD Coastal Cars\nPalm Bay, FL',
  E'Hi {{first_name}}, your {{vehicle}} is ready for pickup.\n\n765 Altara Ln NE, Palm Bay, FL 32907 (back of building)\nLockbox code {{lockbox_code}}\n\nCheck in: {{status_link}}\nHave a great trip! — JD Coastal Cars',
  E'automated', E'Sent when admin marks a vehicle as ready for pickup.'
)
ON CONFLICT (stage) DO UPDATE SET
  name = EXCLUDED.name, channel = EXCLUDED.channel, subject = EXCLUDED.subject,
  body = EXCLUDED.body, sms_body = EXCLUDED.sms_body,
  trigger_type = EXCLUDED.trigger_type, description = EXCLUDED.description;

-- Pre-Pickup Reminder
INSERT INTO email_templates (name, stage, channel, subject, body, sms_body, trigger_type, description) VALUES (
  E'Pre-Pickup Reminder', E'pickup_reminder', E'both',
  E'Pickup tomorrow — your {{vehicle}} is ready ({{booking_code}})',
  E'Hi {{first_name}},\n\nYour rental starts tomorrow. Here''s everything you need.\n\nPickup: {{pickup_date}} at {{pickup_time}}\nVehicle: {{vehicle}}\nReference: {{booking_code}}\nMileage: {{mileage_policy}}\n\nGetting your keys\n765 Altara Ln NE, Palm Bay, FL 32907 — park and walk to the back of the building. Your vehicle has a key lockbox on the window. Enter code {{lockbox_code}}, take the key, and remove the lockbox before driving.\n\nA few house rules: return with the same fuel level, no smoking, no pets ($150 cleaning fee each). Text us when you arrive.\n\nQuestions? Call or text (908) 692-8492.\n\nJD Coastal Cars\nPalm Bay, FL',
  E'Hi {{first_name}}, your {{vehicle}} is ready for pickup tomorrow.\n\nMileage: {{mileage_policy}}\n765 Altara Ln NE, Palm Bay, FL 32907\nLockbox code {{lockbox_code}} (car parked in back)\n\n1. Go to the back of the building\n2. Find the car with the lockbox on the window\n3. Enter {{lockbox_code}}, take the key, remove the lockbox\n\nCheck in: {{portal_link}}\nNeed help? (908) 692-8492 — JD Coastal Cars',
  E'automated', E'Sent automatically 24 hours before the pickup date.'
)
